<?php
require_ once __DIR__ . '/testcase. php'; // NO DB needed
function testNivel() { $tc = new TC(); $tc->eq(1, calcularNivel(0)); $tc->eq(1, calcularNivel(499)); $tc->eq(2, calcularNivel(500)); $tc->eq(2, calcularNivel(999)); $tc->eq(3, calcularNivel(1000)); $tc->eq(3, calcularNivel(1499)); $tc->eq(4, calcularNivel(1500)); list($p,$f)=$tc->s(); echo "nivel PASSED:$p FAILED:$f\n"; return $f===0; } function testLimpiar() { $tc = new TC(); $tc->eq('test', limpiarEntrada('test')); $tc->eq('hola', limpiarEntrada('  hola  ')); $tc->eq('&lt;script&gt;', limpiarEntrada('<script>')); $tc->eq('&lt;?php', limpiarEntrada('<?php')); $tc->eq("O&apos;Reilly", limpiarEntrada("O'Reilly")); list($p,$f)=$tc->s(); echo "limpiar PASSED:$p FAILED:$f\n"; return $f===0; } function testQuiz() { $tc = new TC(); $tc->eq(30, 3*10); $tc->eq(0, strcasecmp('  A ', 'a')); $tc->f(0===strcasecmp('B','a')); $p=[['correcta'=>'A'],['correcta'=>'B'],['correcta'=>'C']]; $r=['A','B','X']; $s=0; foreach($p as $i=>$q){ if(0===strcasecmp($r[$i]??'', $q['correcta'])) $s++; } $tc->eq(2,$s); $tc->eq(20,$s*10); list($p,$f)=$tc->s(); echo "quiz PASSED:$p FAILED:$f\n"; return $f===0; } function testRateLimit() { $tc = new TC(); $a=0; for($i=1;$i<=5;$i++)$a++; $tc->eq(5,$a); $tc->t($a>=5); $api=0; for($i=1;$i<=30;$i++)$api++; $tc->eq(30,$api); $tc->f($api>30); $tc->t(31>30); list($p,$f)=$tc->s(); echo "ratelimit PASSED:$p FAILED:$f\n"; return $f===0; } echo "=== Unit Tests ===\n"; $ok = testNivel() && testLimpiar() && testQuiz() && testRateLimit(); echo $ok ? "PASS\n" : "FAIL\n"; exit($ok ? 0 : 1);